class BLE:
    def __init__(self):
        self.adapter = pygatt.GATTToolBackend()

    @staticmethod
    def notify(handle, value):
        callback_value = hexlify(value)
        print('Response => ', callback_value)

    def send(self, cmd):
        try:
            self.adapter.start()
            device = self.adapter.connect(DEVICE_MAC)
            device.char_write(WRITE_DATA, bytearray(cmd), wait_for_response=True)
            device.subscribe(READ_DATA, callback=self.notify)
        except Exception as e:
            print('Error: ', format(e))
            pass

        finally:
            self.adapter.stop()


if __name__ == '__main__':
    a = BLE()
    a.send([0x00, 0x00, 0x00....])

