```python
from functools import wraps
from pytest import Function


def pytest_collection_modifyitems(items):
    for item in items:
        if 'benchmark' not in getattr(item, 'fixturenames', ()) and isinstance(item, Function):
            item.fixturenames.append('benchmark')
            item._fixtureinfo.argnames += 'benchmark',
            def wrap(obj):
                @wraps(obj)
                def test_wrapper(benchmark, **kwargs):
                    benchmark.pedantic(obj, kwargs=kwargs, iterations=1, rounds=1)
                return test_wrapper
            item.obj = wrap(item.obj)
```
Note that there's no summing of totals, but you could do it by using `benchmark.stats['min']` inside the `test_wrapper` func.

A suggested approach (untested):
```python
class UserLock(Lock):
  def __init__(self, redis, name, user, **kwargs):
    super(UserLock, self).__init__(redis, name, id=str(user), **kwargs)
  def acquire(self, blocking=True):
    locked = super(UserLock, self).acquire(blocking)
    if locked:
      for key in self._client.keys(self._name + ':*'): # cleanup any expired keys
        self._client.del(key)
      self._client.set(self._name + ':' + self._id, self._id, ex=self._expire)
  def extend(self, expire=None):
    super(UserLock, self).extend(expire)
    self._client.set(self._name + ':' + self._id, self._id, ex=expire or self._expire)
```

