@bpatelcs good observation, but the issue that @mjbryant linked is the reason why the code is structured this way. Ultimately, the extra __init__ and __call__ calls will only happen once, so the performance hit is negligible.

```python
import functools


class context_manager_and_decorator(object):

    def __init__(self):
        print 'in __init__'

    def __call__(self, f):
        print 'in __call__'
        @functools.wraps(f)
        def decorated(*args, **kwargs):
            with context_manager_and_decorator():
                return f(*args, **kwargs)
        return decorated

    def __enter__(self):
        print 'in __enter__'
        return self

    def __exit__(self, _exc_type, _exc_value, _exc_traceback):
        print 'in __exit__'


@context_manager_and_decorator()
def decorated_function():
    print 'in decorated_function'

print ''

decorated_function()

print ''

with context_manager_and_decorator():
    print 'in context'
```

